create type commerce_lifecycle_status as enum ('draft','published','paused','archived','disabled');
create type commerce_visibility as enum ('public','private','hidden');
create table products (id uuid primary key default gen_random_uuid(), tenant_id uuid not null, name text not null, slug text not null, short_description text, description text, primary_image text, tags text[] not null default '{}', visibility commerce_visibility not null default 'public', status commerce_lifecycle_status not null default 'draft', preparation_time_minutes integer, sort_order integer not null default 0, nutritional_information jsonb not null default '{}', seo jsonb not null default '{}', open_graph jsonb not null default '{}', audit jsonb not null default '{}', created_at timestamptz not null default now(), updated_at timestamptz, unique (tenant_id, slug));
create table product_media (id uuid primary key default gen_random_uuid(), tenant_id uuid not null, product_id uuid not null references products(id) on delete cascade, url text not null, alt_text text, sort_order integer not null default 0, audit jsonb not null default '{}');
create table categories (id uuid primary key default gen_random_uuid(), tenant_id uuid not null, parent_category_id uuid references categories(id), name text not null, slug text not null, description text, sort_order integer not null default 0, visibility commerce_visibility not null default 'public', status commerce_lifecycle_status not null default 'draft', audit jsonb not null default '{}', unique (tenant_id, slug));
create table menus (id uuid primary key default gen_random_uuid(), tenant_id uuid not null, name text not null, type text not null, visibility jsonb not null default '[]', schedule jsonb not null default '{}', publication jsonb not null default '{}', status commerce_lifecycle_status not null default 'draft', audit jsonb not null default '{}');
create table menu_sections (id uuid primary key default gen_random_uuid(), tenant_id uuid not null, menu_id uuid not null references menus(id) on delete cascade, category_id uuid references categories(id), name text not null, sort_order integer not null default 0, visible boolean not null default true, audit jsonb not null default '{}');
create table menu_items (id uuid primary key default gen_random_uuid(), tenant_id uuid not null, menu_id uuid not null references menus(id) on delete cascade, section_id uuid not null references menu_sections(id) on delete cascade, product_id uuid not null references products(id), sort_order integer not null default 0, visibility_override boolean, price_override jsonb, modifier_group_ids uuid[] not null default '{}', audit jsonb not null default '{}');
create table modifier_groups (id uuid primary key default gen_random_uuid(), tenant_id uuid not null, name text not null, required boolean not null default false, selection text not null check (selection in ('single','multiple')), min_selections integer, max_selections integer, audit jsonb not null default '{}');
create table modifiers (id uuid primary key default gen_random_uuid(), tenant_id uuid not null, name text not null, group_id uuid references modifier_groups(id), audit jsonb not null default '{}');
create table modifier_options (id uuid primary key default gen_random_uuid(), tenant_id uuid not null, modifier_group_id uuid not null references modifier_groups(id) on delete cascade, name text not null, price_adjustment jsonb, selected_by_default boolean not null default false, sort_order integer not null default 0, audit jsonb not null default '{}');
create table combos (id uuid primary key default gen_random_uuid(), tenant_id uuid not null, name text not null, type text not null check (type in ('fixed','configurable','family','promotional')), rules jsonb not null default '[]', pricing jsonb not null default '{}', available boolean not null default true, audit jsonb not null default '{}');
create table combo_items (id uuid primary key default gen_random_uuid(), tenant_id uuid not null, combo_id uuid not null references combos(id) on delete cascade, product_id uuid not null references products(id), quantity integer not null default 1, required boolean not null default true, audit jsonb not null default '{}');
create table availability_rules (id uuid primary key default gen_random_uuid(), tenant_id uuid not null, target_type text not null, target_id uuid not null, branch_id uuid, status text not null check (status in ('available','unavailable','paused','scheduled','sold_out')), reason text, inventory_integration_key text, audit jsonb not null default '{}');
create table branch_availability (id uuid primary key default gen_random_uuid(), tenant_id uuid not null, branch_id uuid not null, status text not null check (status in ('available','unavailable','paused','scheduled','sold_out')), reason text, schedule jsonb not null default '{}', audit jsonb not null default '{}');
create table pricing_rules (id uuid primary key default gen_random_uuid(), tenant_id uuid not null, product_id uuid references products(id), branch_id uuid, menu_id uuid references menus(id), modifier_option_id uuid references modifier_options(id), combo_id uuid references combos(id), base_price jsonb, price_override jsonb, audit jsonb not null default '{}');
alter table products enable row level security; alter table product_media enable row level security; alter table categories enable row level security; alter table menus enable row level security; alter table menu_sections enable row level security; alter table menu_items enable row level security; alter table modifier_groups enable row level security; alter table modifiers enable row level security; alter table modifier_options enable row level security; alter table combos enable row level security; alter table combo_items enable row level security; alter table availability_rules enable row level security; alter table branch_availability enable row level security; alter table pricing_rules enable row level security;
